Here's a modern MSTest test class covering success, failure, and cancellation scenarios:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private MockHttpMessageHandler _handler = null!;
    private DataFetcher _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _handler = new MockHttpMessageHandler();
        _sut = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    [Timeout(5000)] // guard against hanging async tests
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        };

        var result = await _sut.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_OnHttpError()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => _sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        _handler.OnSend = () => cts.Cancel(); // cancel mid-flight

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => _sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_WhenAlreadyCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => _sut.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal test double — avoids heavy mocking frameworks
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } =
            new(HttpStatusCode.OK);

        public Action? OnSend { get; set; }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request,
            CancellationToken cancellationToken)
        {
            OnSend?.Invoke();
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(Response);
        }
    }
}
```

**Key patterns used:**

- **`async Task` test methods** — MSTest natively awaits them; never use `async void`.
- **`[Timeout(5000)]`** — prevents indefinite hangs from unawaited tasks or deadlocks. MSTest enforces this per-test.
- **`Assert.ThrowsExceptionAsync<T>`** — the async counterpart of `ThrowsException`; properly unwraps the `Task`.
- **Custom `HttpMessageHandler`** — avoids mocking `HttpClient` directly (its methods aren't virtual). The `OnSend` callback lets you simulate mid-request cancellation.
- **Two cancellation tests** — one for pre-cancelled tokens, one for cancellation during the request. These are distinct code paths.
